TerraformModules.Example:
terraform {
  required_version = ">= 1.5"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.60.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

locals {
  tags = {
    Environment = "dev"
    Project     = "bnc-bedrock-onboarding"
    Team        = "cloud-platform"
    ManagedBy   = "terraform"
  }
}

module "bedrock_guardrail" {
  source = "../../"

  name        = "bnc-financial-guardrail"
  description = "Production guardrail for BNC AI services - financial services compliance"

  content_filters = [
    { type = "HATE", input_strength = "HIGH", output_strength = "HIGH" },
    { type = "INSULTS", input_strength = "HIGH", output_strength = "HIGH" },
    { type = "SEXUAL", input_strength = "HIGH", output_strength = "HIGH" },
    { type = "VIOLENCE", input_strength = "MEDIUM", output_strength = "HIGH" },
    { type = "MISCONDUCT", input_strength = "HIGH", output_strength = "HIGH" },
    { type = "PROMPT_ATTACK", input_strength = "HIGH", output_strength = "NONE" },
  ]

  denied_topics = [
    {
      name       = "investment_advice"
      definition = "Providing specific investment recommendations, stock picks, or personalized financial advice"
      examples   = ["Should I buy AAPL?", "What's the best ETF?", "Invest my savings"]
    },
    {
      name       = "competitor_info"
      definition = "Sharing confidential information about competitor banks or internal strategies"
      examples   = ["What is Desjardins doing?", "Compare us to TD Bank internally"]
    }
  ]

  pii_entities = [
    { type = "CREDIT_DEBIT_CARD_NUMBER", action = "BLOCK" },
    { type = "US_SOCIAL_SECURITY_NUMBER", action = "BLOCK" },
    { type = "EMAIL", action = "ANONYMIZE" },
    { type = "PHONE", action = "ANONYMIZE" },
    { type = "NAME", action = "ANONYMIZE" },
  ]

  managed_word_lists = ["PROFANITY"]

  tags = local.tags
}

output "guardrail_id" {
  value = module.bedrock_guardrail.guardrail_id
}

output "guardrail_arn" {
  value = module.bedrock_guardrail.guardrail_arn
}

output "guardrail_version" {
  value = module.bedrock_guardrail.guardrail_version
}
